import React, { useEffect, useState } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { View, Text, TouchableOpacity, Alert } from 'react-native';
import RNBiometrics from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkAuthenticationStatus();
  }, []);

  const checkAuthenticationStatus = async () => {
    try {
      const storedAuth = await AsyncStorage.getItem('isAuthenticated');
      if (storedAuth === 'true') {
        setIsAuthenticated(true);
        setIsLoading(false);
        return;
      }
      
      const biometricAuth = await RNBiometrics.isSensorAvailable();
      if (biometricAuth.available) {
        await handleBiometricAuthentication();
      } else {
        setIsLoading(false);
      }
    } catch (error) {
      console.error('Authentication check failed:', error);
      setIsLoading(false);
    }
  };

  const handleBiometricAuthentication = async () => {
    try {
      const { success, signature } = await RNBiometrics.simplePrompt({
        promptMessage: 'Authenticate to access the app'
      });

      if (success) {
        await AsyncStorage.setItem('isAuthenticated', 'true');
        setIsAuthenticated(true);
      } else {
        setIsLoading(false);
      }
    } catch (error) {
      console.error('Biometric authentication failed:', error);
      setIsLoading(false);
    }
  };

  const handlePasswordFallback = async (password) => {
    try {
      // In a real app, validate password against secure storage or API
      if (password === 'secure_password') {
        await AsyncStorage.setItem('isAuthenticated', 'true');
        setIsAuthenticated(true);
      } else {
        Alert.alert('Authentication Failed', 'Invalid password');
      }
    } catch (error) {
      console.error('Password authentication failed:', error);
    }
  };

  const handleLogout = async () => {
    try {
      await AsyncStorage.removeItem('isAuthenticated');
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout failed:', error);
    }
  };

  if (isLoading) {
    return <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}><Text>Loading...</Text></View>;
  }

  if (isAuthenticated) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <Text>Authenticated</Text>
        <TouchableOpacity onPress={handleLogout} style={{ marginTop: 20 }}>
          <Text>Logout</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Biometric Authentication Required</Text>
      <TouchableOpacity onPress={handleBiometricAuthentication} style={{ marginTop: 20 }}>
        <Text>Use Biometrics</Text>
      </TouchableOpacity>
      <TouchableOpacity onPress={() => handlePasswordFallback('secure_password')} style={{ marginTop: 10 }}>
        <Text>Password Fallback</Text>
      </TouchableOpacity>
    </View>
  );
};

export default App;